return [
  {
    json: {
      item_id: '6d6e2f96ab2c4f86c6bfe17f0f3d5c21d7839ed4f3d8fbf35bc7f7f5ec34f7a1',
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      title: 'Example normalized item before Qdrant gating',
      content_text: 'This example item already passed 00_common_normalize_text_object and is about to enter the cheap deterministic prefilter before vector search.',
      upstream_summary: '',
      dedupe_action: 'full_push',
      status: 'raw'
    }
  }
];

const requiredFields = ['item_id', 'source_type', 'source_name', 'title', 'content_text'];
const missingFields = requiredFields.filter((field) => !String($json[field] || '').trim());
if (missingFields.length) {
  throw new Error(`NormalizedTextObject missing required fields: ${missingFields.join(', ')}`);
}

const contentText = String($json.content_text || '').replace(/\r\n/g, '\n').trim();
const upstreamSummary = String($json.upstream_summary || '').replace(/\r\n/g, '\n').trim();
const title = String($json.title || '').trim();
const searchTextMaxChars = Math.max(200, Number($env.EMBEDDING_INPUT_MAX_CHARS || 8000));
const searchTextMinChars = Math.max(40, Number($env.QDRANT_SEARCH_MIN_CHARS || 80));
const searchText = [title, upstreamSummary, contentText]
  .filter(Boolean)
  .join('\n\n')
  .slice(0, searchTextMaxChars);
const shouldContinueToQdrant = searchText.length >= searchTextMinChars;
const prefilterReason = shouldContinueToQdrant
  ? ''
  : `search_text shorter than ${searchTextMinChars} chars after deterministic prefilter`;

return {
  json: {
    ...$json,
    content_text: contentText,
    search_text: searchText,
    search_text_chars: searchText.length,
    prefilter_action: shouldContinueToQdrant ? 'pass' : 'skip',
    prefilter_reason: prefilterReason,
    should_continue_to_qdrant: shouldContinueToQdrant,
    dedupe_action: shouldContinueToQdrant ? String($json.dedupe_action || 'full_push').trim() || 'full_push' : 'silent',
    notification_mode: shouldContinueToQdrant ? String($json.notification_mode || '').trim() : 'silent',
    should_write_to_vault: shouldContinueToQdrant ? $json.should_write_to_vault : false,
    should_notify: shouldContinueToQdrant ? $json.should_notify : false,
    should_upsert_qdrant: shouldContinueToQdrant ? $json.should_upsert_qdrant : false,
    should_continue_to_llm: shouldContinueToQdrant ? true : false,
    status: shouldContinueToQdrant ? String($json.status || 'raw').trim() || 'raw' : 'deduped',
    qdrant_operation: shouldContinueToQdrant ? String($json.qdrant_operation || 'skipped').trim() || 'skipped' : 'skipped',
    qdrant_upsert_response: null
  }
};
